// build-store-profile — Read Upstream Artifacts
// Reads shopify-import.json from disk and retrieves intake payload from input.
// Validates all required upstream inputs are present.

const fs   = require('fs');
const path = require('path');

const input             = $input.first().json;
const runtimeConfig     = input.runtime_config;
const intakePayload     = input.normalized_intake_payload;
const projectId         = input.project_id;

if (!runtimeConfig || !intakePayload || !projectId) {
  throw new Error(
    'MISSING_RUNTIME_CONFIG: build-store-profile requires runtime_config, normalized_intake_payload, and project_id'
  );
}

const projectRoot = runtimeConfig.project_root;

// ── Validate intake fields required by this workflow ─────────────────────
const intakeRequired = ['project_id', 'primary_market', 'primary_language', 'primary_currency', 'vertical', 'price_positioning'];
const intakeMissing  = intakeRequired.filter((f) => !intakePayload[f]);
if (intakeMissing.length > 0) {
  throw new Error(`MISSING_ARTIFACT: intake_payload is missing required fields: ${intakeMissing.join(', ')}`);
}

// ── Read shopify-import.json ──────────────────────────────────────────────
const shopifyImportPath = path.join(projectRoot, projectId, 'shopify-import.json');

if (!fs.existsSync(shopifyImportPath)) {
  throw new Error(`MISSING_ARTIFACT: shopify-import.json not found at ${shopifyImportPath}`);
}

let shopifyImport;
try {
  shopifyImport = JSON.parse(fs.readFileSync(shopifyImportPath, 'utf8'));
} catch (err) {
  throw new Error(`PARSE_ERROR: Failed to parse shopify-import.json: ${err.message}`);
}

// ── project_id consistency check ──────────────────────────────────────────
if (shopifyImport.project_id !== projectId) {
  throw new Error(
    `PROJECT_ID_MISMATCH: shopify-import.json project_id "${shopifyImport.project_id}" does not match runtime project_id "${projectId}"`
  );
}

// ── Validate shopify-import has required data ─────────────────────────────
const rawShopData    = shopifyImport.raw_shop_data || {};
const importSummary  = shopifyImport.import_summary || {};

if (!rawShopData.shop_name) {
  throw new Error('MISSING_ARTIFACT: shopify-import.json raw_shop_data.shop_name is empty');
}
if (!rawShopData.shop_domain) {
  throw new Error('MISSING_ARTIFACT: shopify-import.json raw_shop_data.shop_domain is empty');
}

return [{
  json: {
    project_id:      projectId,
    runtime_config:  runtimeConfig,
    intake_payload:  intakePayload,
    shopify_import:  shopifyImport,
    raw_shop_data:   rawShopData,
    import_summary:  importSummary,
  },
}];

// build-store-profile — Map Fields and Validate
// Maps intake + Shopify data to store-profile schema fields.
// Derives catalog_type from active product count.
// Validates assembled object against schemas/store-profile.schema.json.
// Writes store-profile.json atomically on success; quarantines on failure.

const fs   = require('fs');
const path = require('path');

const input          = $input.first().json;
const intakePayload  = input.intake_payload;
const rawShopData    = input.raw_shop_data;
const importSummary  = input.import_summary;
const runtimeConfig  = input.runtime_config;
const projectId      = input.project_id;
const projectRoot    = runtimeConfig.project_root;

// ── Derive catalog_type from active product count ─────────────────────────
const activeCount = typeof importSummary.active_product_count === 'number'
  ? importSummary.active_product_count
  : 0;

let catalogType;
if (activeCount === 0) {
  catalogType = 'small-curated-catalog'; // provisional — no products yet
} else if (activeCount === 1) {
  catalogType = 'single-product';
} else if (activeCount <= 15) {
  catalogType = 'small-curated-catalog';
} else if (activeCount <= 200) {
  catalogType = 'broad-catalog';
} else {
  catalogType = 'mixed-catalog';
}

// ── Map publish_mode → operating_mode ────────────────────────────────────
const OPERATING_MODE_MAP = {
  'no-publish':       'draft-first',
  'draft-only':       'draft-first',
  'draft-and-review': 'staging-first',
};
const operatingMode = OPERATING_MODE_MAP[intakePayload.publish_mode] || 'draft-first';

// ── Assemble store-profile (only schema-defined fields) ───────────────────
// store-profile.schema.json uses additionalProperties: false.
// Do NOT add fields not defined in the schema.
const storeProfile = {
  store_id:         projectId,
  store_name:       rawShopData.shop_name,
  store_type:       intakePayload.store_type       || 'multi-product-store',
  platform:         'shopify',
  business_model:   intakePayload.business_model   || 'ecommerce',
  primary_market:   intakePayload.primary_market,
  target_markets:   intakePayload.target_markets   || [intakePayload.primary_market],
  primary_language: intakePayload.primary_language,
  languages:        intakePayload.languages        || [intakePayload.primary_language],
  primary_currency: intakePayload.primary_currency,
  currencies:       intakePayload.currencies       || [intakePayload.primary_currency],
  vertical:         intakePayload.vertical,
  price_positioning:intakePayload.price_positioning,
  catalog_type:     catalogType,
  brand_maturity:   'new',
  operating_mode:   operatingMode,
  domain:           rawShopData.shop_domain,
};

// Add optional notes field only if special_notes is present
if (intakePayload.special_notes) {
  storeProfile.notes = intakePayload.special_notes;
}

// ── AJV schema validation ─────────────────────────────────────────────────
const schemaPath = path.join(runtimeConfig.ajv_schema_path, 'store-profile.schema.json');

if (!fs.existsSync(schemaPath)) {
  throw new Error(`SCHEMA_LOAD_ERROR: store-profile.schema.json not found at ${schemaPath}`);
}

const schema = JSON.parse(fs.readFileSync(schemaPath, 'utf8'));

let AjvClass;
try {
  AjvClass = require('ajv/dist/2020');
} catch {
  try {
    AjvClass = require('ajv');
  } catch (err) {
    throw new Error(
      `SCHEMA_LOAD_ERROR: AJV not available in n8n environment: ${err.message}. ` +
      'Install ajv@8 in the n8n node_modules directory.'
    );
  }
}

const ajv      = new AjvClass({ allErrors: true, strict: false });
const validate = ajv.compile(schema);
const valid    = validate(storeProfile);

if (!valid) {
  // ── Quarantine rejected artifact ────────────────────────────────────────
  const quarantineDir = path.join(projectRoot, projectId, '.runtime', 'quarantine');
  fs.mkdirSync(quarantineDir, { recursive: true });
  const ts           = new Date().toISOString().replace(/[:.]/g, '-');
  const quarantinePath = path.join(quarantineDir, `store-profile.${ts}.rejected.json`);
  const quarantinePayload = {
    quarantine_reason: 'SCHEMA_VIOLATION',
    artifact_name:     'store-profile',
    workflow_id:       'build-store-profile',
    validation_errors: validate.errors,
    timestamp:         new Date().toISOString(),
    project_id:        projectId,
    artifact_payload:  storeProfile,
  };
  fs.writeFileSync(quarantinePath, JSON.stringify(quarantinePayload, null, 2), 'utf8');

  const errorSummary = (validate.errors || [])
    .map((e) => `${e.instancePath || '(root)'} ${e.message}`)
    .join('; ');
  throw new Error(
    `SCHEMA_VIOLATION: store-profile failed validation. Quarantined to ${quarantinePath}. ` +
    `Errors: ${errorSummary}`
  );
}

// ── Atomic write ──────────────────────────────────────────────────────────
const projectDir  = path.join(projectRoot, projectId);
const finalPath   = path.join(projectDir, 'store-profile.json');
const tmpPath     = path.join(projectDir, 'store-profile.tmp.json');

fs.mkdirSync(projectDir, { recursive: true });
fs.writeFileSync(tmpPath, JSON.stringify(storeProfile, null, 2), 'utf8');
fs.renameSync(tmpPath, finalPath);

// ── Update checkpoint ─────────────────────────────────────────────────────
const checkpointPath = path.join(projectRoot, projectId, '.runtime', 'checkpoint.json');
const now = new Date().toISOString();
try {
  const checkpoint = JSON.parse(fs.readFileSync(checkpointPath, 'utf8'));
  checkpoint.completed_workflows.push({
    workflow_id:     'build-store-profile',
    completed_at:    now,
    output_artifact: 'store-profile.json',
    status:          'SUCCESS',
  });
  checkpoint.last_updated_timestamp = now;
  checkpoint.next_workflow          = 'build-market-intelligence';
  const cpTmp = checkpointPath + '.tmp';
  fs.writeFileSync(cpTmp, JSON.stringify(checkpoint, null, 2), 'utf8');
  fs.renameSync(cpTmp, checkpointPath);
} catch { /* checkpoint update failure is non-fatal in Phase 12 — log it but don't halt */ }

// ── Append to execution log ───────────────────────────────────────────────
const logPath = path.join(projectRoot, projectId, '.runtime', 'execution-log.json');
try {
  const logData = fs.existsSync(logPath)
    ? JSON.parse(fs.readFileSync(logPath, 'utf8'))
    : { entries: [] };
  logData.entries.push({
    timestamp:        now,
    execution_run_id: 'run-unknown',
    level:            'INFO',
    event_type:       'ARTIFACT_WRITE',
    workflow_id:      'build-store-profile',
    artifact:         'store-profile.json',
    message:          `store-profile.json written. catalog_type=${catalogType}, active_products=${activeCount}`,
  });
  const logTmp = logPath + '.tmp';
  fs.writeFileSync(logTmp, JSON.stringify(logData, null, 2), 'utf8');
  fs.renameSync(logTmp, logPath);
} catch { /* log write failure is non-fatal */ }

return [{
  json: {
    project_id:    projectId,
    artifact_path: finalPath,
    artifact_name: 'store-profile',
    store_profile: storeProfile,
    runtime_config:runtimeConfig,
    status:        'SUCCESS',
    notes: [
      activeCount === 0
        ? 'WARNING: No active products found in Shopify import. catalog_type defaulted to small-curated-catalog.'
        : null,
      importSummary.pagination_note || null,
    ].filter(Boolean),
  },
}];
